import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [requests, setRequests] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const adminPassword = "admin123"; // तुमचा पासवर्ड

  // डेटाबेस मधून डेटा मिळवणे
  const fetchData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
    } catch (err) {
      console.error("Fetch error:", err);
    }
  };

  useEffect(() => {
    if (isLoggedIn) fetchData();
  }, [isLoggedIn]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === adminPassword) setIsLoggedIn(true);
    else alert("Wrong Password!");
  };

  // स्टेटस, प्रोग्रेस आणि पेमेंट अपडेट करणे
  const handleUpdate = async (id) => {
    const newStatus = document.getElementById(`status-${id}`).value;
    const newProgress = document.getElementById(`progress-${id}`).value;
    const newPayment = document.getElementById(`pay-${id}`).value;

    // मायनस व्हॅल्यू रोखण्यासाठी लॉजिक
    let fixedProgress = Math.max(0, Math.min(100, newProgress));

    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, {
        status: newStatus,
        progress: fixedProgress,
        paymentStatus: newPayment
      });
      alert("Project Data Updated Successfully!");
      fetchData(); // डेटा रिफ्रेश करा
    } catch (err) {
      console.error("Update error:", err);
    }
  };

  // प्रोजेक्ट डिलीट करणे
  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this request?")) {
      try {
        await axios.delete(`http://localhost:5000/api/delete-request/${id}`);
        alert("Request Deleted!");
        fetchData();
      } catch (err) {
        console.error("Delete error:", err);
      }
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="container py-5 mt-5">
        <div className="row justify-content-center">
          <div className="col-md-4 text-center card shadow-lg p-4 border-0 rounded-4">
            <h3 className="fw-bold mb-4">Admin Dashboard</h3>
            <form onSubmit={handleLogin}>
              <input 
                type="password" 
                placeholder="Enter Admin Password" 
                className="form-control mb-3 text-center" 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                required 
              />
              <button className="btn btn-dark w-100 fw-bold shadow-sm">Login</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container py-5">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold text-primary">Manage Project Requests</h2>
        <button className="btn btn-danger btn-sm px-4 shadow-sm" onClick={() => setIsLoggedIn(false)}>Logout</button>
      </div>

      <div className="table-responsive shadow-lg rounded-4 p-3 bg-white border">
        <table className="table table-hover align-middle">
          <thead className="table-dark text-center">
            <tr>
              <th>Date</th>
              <th>Client</th>
              <th>Payment</th>
              <th>Payment Status</th>
              <th>Progress (%)</th>
              <th>Work Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody className="text-center">
            {requests.map((req) => (
              <tr key={req._id}>
                <td>{new Date(req.date).toLocaleDateString()}</td>
                <td className="fw-bold">{req.fullName}</td>
                <td><span className="badge bg-secondary">{req.paymentMethod}</span></td>
                <td>
                  <select id={`pay-${req._id}`} className="form-select form-select-sm" defaultValue={req.paymentStatus}>
                    <option value="Unpaid">Unpaid</option>
                    <option value="Paid">Paid</option>
                  </select>
                </td>
                <td>
                  <input 
                    type="number" 
                    id={`progress-${req._id}`} 
                    className="form-control form-control-sm mx-auto" 
                    defaultValue={req.progress} 
                    min="0" 
                    max="100" 
                    style={{ width: '80px' }} 
                  />
                </td>
                <td>
                  <select id={`status-${req._id}`} className="form-select form-select-sm" defaultValue={req.status}>
                    <option value="Pending">Pending</option>
                    <option value="In Progress">In Progress</option>
                    <option value="Completed">Completed</option>
                  </select>
                </td>
                <td>
                  <div className="btn-group shadow-sm">
                    <button className="btn btn-success btn-sm px-3 fw-bold" onClick={() => handleUpdate(req._id)}>Update</button>
                    <button className="btn btn-outline-danger btn-sm px-3" onClick={() => handleDelete(req._id)}>Delete</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Admin;
